#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N, X; scanf("%d %d", &N, &X);
        int cur = X, ans = X;
        for(int i=0;i<N;i++){
            int a; scanf("%d", &a);
            cur += a;
            if(cur > ans) ans = cur;
        }
        printf("%d\n", ans);
    }
    return 0;
}

