using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N, X; cin>>N>>X;
        long long cur = X, ans = X;
        for(int i=0;i<N;i++){
            int a; cin>>a;
            cur += a;
            ans = max(ans, cur);
        }
        cout<<ans<<"\n";
    }
    return 0;
}

